Window.Resources.MotionClip:
@sequence
{
@set
{
    $part.MotionStatusText.Text = "ARMING / 00 NODES";
    $part.MotionClockText.Text = "T + 00:00.000";
    $part.MotionTransactionText.Text = "OPEN";
    $part.MotionPhaseIndex.Text = "00";
    $part.MotionFieldReadout.Text = "FIELD LOCKED";
    $part.MotionReactorState.Text = "STANDBY";
}
@parallel
{
    @animate with Tween(90ms) { @from { $part.MotionOrbTween.Opacity = current; $part.MotionOrbSpring.Opacity = current; $part.MotionOrbPresence.Opacity = current; } @to { $part.MotionOrbTween.Opacity = 0; $part.MotionOrbSpring.Opacity = 0; $part.MotionOrbPresence.Opacity = 0; } }
    @animate with Tween(90ms) { @from { $part.MotionStarA.Opacity = current; $part.MotionStarB.Opacity = current; $part.MotionStarC.Opacity = current; $part.MotionStarD.Opacity = current; } @to { $part.MotionStarA.Opacity = 0; $part.MotionStarB.Opacity = 0; $part.MotionStarC.Opacity = 0; $part.MotionStarD.Opacity = 0; } }
    @animate with Tween(90ms) { @from { $part.MotionActIgnition.Opacity = current; $part.MotionActOrbit.Opacity = current; $part.MotionActCommit.Opacity = current; } @to { $part.MotionActIgnition.Opacity = 0.38; $part.MotionActOrbit.Opacity = 0.38; $part.MotionActCommit.Opacity = 0.38; } }
    @animate with Tween(90ms) { @from { $part.MotionCore.Scale = current; $part.MotionCoreHalo.Scale = current; $part.MotionCoreRing.Scale = current; } @to { $part.MotionCore.Scale = 0.72; $part.MotionCoreHalo.Scale = 0.68; $part.MotionCoreRing.Scale = 0.74; } }
}
@set
{
    $part.MotionPhaseIndex.Text = "01";
    $part.MotionStatusText.Text = "IGNITION / 04 NODES";
    $part.MotionReactorState.Text = "CLOCK PRIMED";
}
@parallel
{
    @animate with Spring(360, 25) { @from { $part.MotionCore.Scale = 0.72; } @to { $part.MotionCore.Scale = 1.08; } }
    @animate with Spring(300, 23) { @from { $part.MotionCoreHalo.Scale = 0.68; } @to { $part.MotionCoreHalo.Scale = 1; } }
    @animate with Tween(420ms, EaseOut) { @from { $part.MotionCoreHalo.Opacity = 0.08; } @to { $part.MotionCoreHalo.Opacity = 0.42; } }
    @animate with Spring(480, 31) { @from { $part.MotionCoreRing.Scale = 0.74; } @to { $part.MotionCoreRing.Scale = 1; } }
    @animate with Tween(260ms, EaseOut) { @from { $part.MotionActIgnition.Opacity = current; } @to { $part.MotionActIgnition.Opacity = 1; } }
}
@set
{
    $part.MotionPhaseIndex.Text = "02";
    $part.MotionClockText.Text = "T + 00:00.620";
    $part.MotionStatusText.Text = "TRAJECTORIES / 15 NODES";
    $part.MotionFieldReadout.Text = "FIELD IN MOTION";
    $part.MotionReactorState.Text = "COMPOSING";
}
@parallel
{
    @keyframes duration 1780ms
    {
        @animate 0%..24% with EaseInOut { @from { $part.MotionOrbTween.TranslateX = -220; $part.MotionOrbTween.TranslateY = 0; } @to { $part.MotionOrbTween.TranslateX = 0; $part.MotionOrbTween.TranslateY = -118; } }
        @animate 24%..50% with EaseInOut { @from { $part.MotionOrbTween.TranslateX = 0; $part.MotionOrbTween.TranslateY = -118; } @to { $part.MotionOrbTween.TranslateX = 220; $part.MotionOrbTween.TranslateY = 0; } }
        @animate 50%..76% with EaseInOut { @from { $part.MotionOrbTween.TranslateX = 220; $part.MotionOrbTween.TranslateY = 0; } @to { $part.MotionOrbTween.TranslateX = 0; $part.MotionOrbTween.TranslateY = 118; } }
        @animate 76%..100% with EaseInOut { @from { $part.MotionOrbTween.TranslateX = 0; $part.MotionOrbTween.TranslateY = 118; } @to { $part.MotionOrbTween.TranslateX = -180; $part.MotionOrbTween.TranslateY = 30; } }
    }
    @animate with Tween(180ms, EaseOut) { @from { $part.MotionOrbTween.Opacity = 0; } @to { $part.MotionOrbTween.Opacity = 1; } }
    @animate with Spring(310, 19) { @from { $part.MotionOrbSpring.TranslateX = -42; } @to { $part.MotionOrbSpring.TranslateX = 166; } }
    @animate with Spring(420, 24) { @from { $part.MotionOrbSpring.TranslateY = 12; } @to { $part.MotionOrbSpring.TranslateY = 76; } }
    @animate with Spring(520, 30) { @from { $part.MotionOrbSpring.Scale = 0.35; } @to { $part.MotionOrbSpring.Scale = 1; } }
    @animate with Tween(280ms, EaseOut) { @from { $part.MotionOrbSpring.Opacity = 0; } @to { $part.MotionOrbSpring.Opacity = 1; } }
    @animate with Spring(560, 36) { @from { $part.MotionOrbPresence.TranslateX = 0; } @to { $part.MotionOrbPresence.TranslateX = -108; } }
    @animate with Spring(600, 38) { @from { $part.MotionOrbPresence.TranslateY = 0; } @to { $part.MotionOrbPresence.TranslateY = -82; } }
    @animate with Spring(440, 27) { @from { $part.MotionOrbPresence.Scale = 0.05; } @to { $part.MotionOrbPresence.Scale = 1; } }
    @animate with Tween(520ms, EaseOut) { @from { $part.MotionOrbPresence.Opacity = 0; } @to { $part.MotionOrbPresence.Opacity = 1; } }
    @animate with Tween(920ms, EaseIn) { @from { $part.MotionStarA.TranslateX = -80; $part.MotionStarA.TranslateY = -90; } @to { $part.MotionStarA.TranslateX = 720; $part.MotionStarA.TranslateY = 250; } }
    @animate with Tween(180ms, EaseOut) { @from { $part.MotionStarA.Opacity = 0; } @to { $part.MotionStarA.Opacity = 0.72; } }
    @animate with Tween(1180ms, EaseIn) { @from { $part.MotionStarB.TranslateX = -180; $part.MotionStarB.TranslateY = -120; } @to { $part.MotionStarB.TranslateX = 640; $part.MotionStarB.TranslateY = 280; } }
    @animate with Tween(240ms, EaseOut) { @from { $part.MotionStarB.Opacity = 0; } @to { $part.MotionStarB.Opacity = 0.82; } }
    @animate with Tween(1460ms, EaseIn) { @from { $part.MotionStarC.TranslateX = -280; $part.MotionStarC.TranslateY = -100; } @to { $part.MotionStarC.TranslateX = 520; $part.MotionStarC.TranslateY = 260; } }
    @animate with Tween(320ms, EaseOut) { @from { $part.MotionStarC.Opacity = 0; } @to { $part.MotionStarC.Opacity = 0.68; } }
    @animate with Tween(1020ms, EaseIn) { @from { $part.MotionStarD.TranslateX = -420; $part.MotionStarD.TranslateY = -150; } @to { $part.MotionStarD.TranslateX = 380; $part.MotionStarD.TranslateY = 220; } }
    @animate with Tween(220ms, EaseOut) { @from { $part.MotionStarD.Opacity = 0; } @to { $part.MotionStarD.Opacity = 0.74; } }
    @animate with Tween(90ms) { @from { $part.MotionActOrbit.Opacity = current; } @to { $part.MotionActOrbit.Opacity = 1; } }
}
@set
{
    $part.MotionPhaseIndex.Text = "03";
    $part.MotionClockText.Text = "T + 00:02.400";
    $part.MotionStatusText.Text = "COMMITTING / 06 NODES";
    $part.MotionTransactionText.Text = "COMMITTING";
    $part.MotionReactorState.Text = "SETTLING";
}
@parallel
{
    @animate with Spring(620, 42) { @from { $part.MotionCore.Scale = 1.08; } @to { $part.MotionCore.Scale = 1; } }
    @animate with Tween(520ms, EaseOut) { @from { $part.MotionCoreHalo.Scale = 1; $part.MotionCoreHalo.Opacity = 0.42; } @to { $part.MotionCoreHalo.Scale = 1.28; $part.MotionCoreHalo.Opacity = 0.14; } }
    @animate with Tween(260ms, EaseOut) { @from { $part.MotionActCommit.Opacity = current; } @to { $part.MotionActCommit.Opacity = 1; } }
    @animate with Tween(180ms, EaseIn) { @from { $part.MotionStarA.Opacity = current; } @to { $part.MotionStarA.Opacity = 0; } }
    @animate with Tween(220ms, EaseIn) { @from { $part.MotionStarB.Opacity = current; } @to { $part.MotionStarB.Opacity = 0; } }
    @animate with Tween(260ms, EaseIn) { @from { $part.MotionStarC.Opacity = current; } @to { $part.MotionStarC.Opacity = 0; } }
    @animate with Tween(200ms, EaseIn) { @from { $part.MotionStarD.Opacity = current; } @to { $part.MotionStarD.Opacity = 0; } }
}
@set
{
    $part.MotionClockText.Text = "T + 00:02.920";
    $part.MotionStatusText.Text = "SETTLED / GRAPH IDLE";
    $part.MotionTransactionText.Text = "COMMITTED";
    $part.MotionFieldReadout.Text = "FIELD STABLE";
    $part.MotionReactorState.Text = "AT REST";
}
}

@sequence
{
    @parallel
    {
        @animate with Tween(80ms) { @from { $part.PipelineRelay.Opacity = current; $part.PipelineInput.Opacity = current; $part.PipelineState.Opacity = current; $part.PipelineMeasure.Opacity = current; $part.PipelineArrange.Opacity = current; $part.PipelineCache.Opacity = current; $part.PipelineHit.Opacity = current; $part.PipelineBackend.Opacity = current; } @to { $part.PipelineRelay.Opacity = 0.24; $part.PipelineInput.Opacity = 0.24; $part.PipelineState.Opacity = 0.24; $part.PipelineMeasure.Opacity = 0.24; $part.PipelineArrange.Opacity = 0.24; $part.PipelineCache.Opacity = 0.24; $part.PipelineHit.Opacity = 0.24; $part.PipelineBackend.Opacity = 0.24; } }
        @animate with Tween(80ms) { @from { $part.PipelineRelay.Scale = current; $part.PipelineInput.Scale = current; $part.PipelineState.Scale = current; $part.PipelineMeasure.Scale = current; $part.PipelineArrange.Scale = current; $part.PipelineCache.Scale = current; $part.PipelineHit.Scale = current; $part.PipelineBackend.Scale = current; } @to { $part.PipelineRelay.Scale = 0.94; $part.PipelineInput.Scale = 0.94; $part.PipelineState.Scale = 0.94; $part.PipelineMeasure.Scale = 0.94; $part.PipelineArrange.Scale = 0.94; $part.PipelineCache.Scale = 0.94; $part.PipelineHit.Scale = 0.94; $part.PipelineBackend.Scale = 0.94; } }
    }
    @parallel { @animate with Tween(150ms, EaseOut) { @from { $part.PipelineRelay.Opacity = 0.24; } @to { $part.PipelineRelay.Opacity = 1; } } @animate with Spring(700, 45) { @from { $part.PipelineRelay.Scale = 0.94; } @to { $part.PipelineRelay.Scale = 1; } } }
    @parallel { @animate with Tween(150ms, EaseOut) { @from { $part.PipelineInput.Opacity = 0.24; } @to { $part.PipelineInput.Opacity = 1; } } @animate with Spring(700, 45) { @from { $part.PipelineInput.Scale = 0.94; } @to { $part.PipelineInput.Scale = 1; } } }
    @parallel { @animate with Tween(150ms, EaseOut) { @from { $part.PipelineState.Opacity = 0.24; } @to { $part.PipelineState.Opacity = 1; } } @animate with Spring(700, 45) { @from { $part.PipelineState.Scale = 0.94; } @to { $part.PipelineState.Scale = 1; } } }
    @parallel { @animate with Tween(150ms, EaseOut) { @from { $part.PipelineMeasure.Opacity = 0.24; } @to { $part.PipelineMeasure.Opacity = 1; } } @animate with Spring(700, 45) { @from { $part.PipelineMeasure.Scale = 0.94; } @to { $part.PipelineMeasure.Scale = 1; } } }
    @parallel { @animate with Tween(150ms, EaseOut) { @from { $part.PipelineArrange.Opacity = 0.24; } @to { $part.PipelineArrange.Opacity = 1; } } @animate with Spring(700, 45) { @from { $part.PipelineArrange.Scale = 0.94; } @to { $part.PipelineArrange.Scale = 1; } } }
    @parallel { @animate with Tween(150ms, EaseOut) { @from { $part.PipelineCache.Opacity = 0.24; } @to { $part.PipelineCache.Opacity = 1; } } @animate with Spring(700, 45) { @from { $part.PipelineCache.Scale = 0.94; } @to { $part.PipelineCache.Scale = 1; } } }
    @parallel { @animate with Tween(150ms, EaseOut) { @from { $part.PipelineHit.Opacity = 0.24; } @to { $part.PipelineHit.Opacity = 1; } } @animate with Spring(700, 45) { @from { $part.PipelineHit.Scale = 0.94; } @to { $part.PipelineHit.Scale = 1; } } }
    @parallel { @animate with Tween(150ms, EaseOut) { @from { $part.PipelineBackend.Opacity = 0.24; } @to { $part.PipelineBackend.Opacity = 1; } } @animate with Spring(700, 45) { @from { $part.PipelineBackend.Scale = 0.94; } @to { $part.PipelineBackend.Scale = 1; } } }
}

Window.Resources.Aspect:
@handle Reactor;
@handle Pipeline;
@when $PageMotion.Visibility
{
    @if value == Visible { @run $ReactorReplay as Reactor; }
    @if value == Collapsed { @cancel Reactor; }
}
@when $ReplayMotionButton.IsPressed { @run $ReactorReplay as Reactor; }
@on PipelineRequested { @run $PipelineReplay as Pipeline; }

@when Visibility
{
    @if Visibility == Visible
    {
        @parallel
        {
            @animate with Tween(360ms, EaseOut) { @from { Opacity = 0.25; } @to { Opacity = 1; } }
            @animate with Spring(460, 38) { @from { TranslateY = 18; } @to { TranslateY = 0; } }
        }
    }
}

@default
{
    FontFamily = "Segoe UI Variable Text";
    FontSize = 14;
    Foreground = $PaperBrush;
}

@default
{
    FontFamily = "Cascadia Mono SemiBold";
    FontSize = 12;
    Background = $TransparentBrush;
    Foreground = $SlateBrush;
    BorderBrush = $TransparentBrush;
    BorderThickness = "0";
    Padding = "18,10,12,10";
}
@when IsChecked
{
    Background = $CyanWashBrush;
    Foreground = $PaperBrush;
    BorderBrush = $LimeBrush;
}
@when IsMouseOver
{
    @if IsMouseOver == true
    {
        @parallel
        {
            @animate with $NavHoverIn { @from { Background = current; } @to { Background = $CyanWashBrush; } }
            @animate with $NavTextHover { @from { Foreground = current; } @to { Foreground = $PaperBrush; } }
        }
    }
    @if IsMouseOver == false
    {
        @parallel
        {
            @animate with $NavHoverOut { @from { Background = current; } @to { Background = $TransparentBrush; } }
            @animate with $NavTextHover { @from { Foreground = current; } @to { Foreground = $SlateBrush; } }
        }
    }
}
@template
{












}

@default
{
    FontFamily = "Cascadia Mono SemiBold";
    FontSize = 12;
    Background = $TransparentBrush;
    Foreground = $PaperBrush;
    BorderBrush = $LineStrongBrush;
    BorderThickness = "1";
    Padding = "18,11,18,11";
}
@when IsMouseOver
{
    Background = $CyanWashBrush;
    Foreground = $CyanBrush;
    BorderBrush = $CyanBrush;
}

@default
{
    FontFamily = "Cascadia Mono SemiBold";
    FontSize = 12;
    Background = $LimeBrush;
    Foreground = $InkBrush;
    BorderBrush = $LimeBrush;
    BorderThickness = "1";
    Padding = "20,12,20,12";
}
@when IsMouseOver
{
    Background = $CyanBrush;
    BorderBrush = $CyanBrush;
}

TextBlock.Text:
public partial class MainWindow : Window
{
  private void OnLaunch(
    UiElementId sender,
    RoutedEventArgs args)
  {
    Launch.Motion()
      .Scale.To(
        1.08f,
        Motion.Spring<float>());
  }
}
